test_that("smoke_simple_heading: H1 heading converts to ATX markdown", {
  result <- jsonlite::fromJSON(convert(html = "<h1>Title</h1>", options = HtmlOutputConfig$default()), simplifyVector = FALSE)
  expect_true(grepl("# Title", result$content, fixed = TRUE))
})

test_that("smoke_simple_paragraph: Simple paragraph converts correctly", {
